    def test_inventory_lists_existing_debugger_subsystems(self) -> None:
        report = build_inventory()
        subsystem_ids = {subsystem["id"] for subsystem in report["subsystems"]}

        self.assertIn("boss_ai", subsystem_ids)
        self.assertIn("damage", subsystem_ids)
        self.assertIn("trace_runtime", subsystem_ids)

    def test_trace_runtime_read_word_is_little_endian_and_restores_wram_bank(self) -> None:
        class FakeMemory:
            def __init__(self) -> None:
                self.current_wram_bank = 1
                self.values = {0xFF70: 1, 0xD000: 0x11, 0xD001: 0x22}
                self.banked_values = {(2, 0xD000): 0xAA, (2, 0xD001): 0xBB}

            def __getitem__(self, key):
                if isinstance(key, tuple):
                    raise TypeError("force FF70 fallback")
                if key == 0xFF70:
                    return self.current_wram_bank
                if 0xD000 <= key <= 0xDFFF:
                    return self.banked_values.get((self.current_wram_bank, key), self.values.get(key, 0))
                return self.values.get(key, 0)

            def __setitem__(self, key, value) -> None:
                if key == 0xFF70:
                    self.current_wram_bank = int(value)
                    self.values[key] = int(value)
                else:
                    self.values[key] = int(value)

        class FakePyBoy:
            def __init__(self) -> None:
                self.memory = FakeMemory()

        pyboy = FakePyBoy()

        self.assertEqual(read_word(pyboy, Symbol(2, 0xD000)), 0xBBAA)
        self.assertEqual(pyboy.memory[0xFF70], 1)

    def test_damage_taint_sub_a_clears_a_taint(self) -> None:
        def instruction(pc: int, opcode: int, operand: tuple[int, ...] = ()) -> Instruction:
            operand_bytes = bytes(operand)
            return Instruction(
                bank=0,
                pc=pc,
                opcode=opcode,
                operand=operand_bytes,
                length=1 + len(operand_bytes),
                mnemonic=render_mnemonic(opcode, operand_bytes),
            )

        engine = TaintEngine(sinks=[DamageSink("wCurDamage", 0xD141, 1)])
        engine.seed_reg("a", "source:a")
        report = engine.run(
            [
                instruction(0x1000, 0x97),
                instruction(0x1001, 0xEA, (0x41, 0xD1)),
            ],
            [
                SyntheticFrame(seq=0, bank=0, pc=0x1000, pc_label="ClearA", A=0x2A),
                SyntheticFrame(seq=1, bank=0, pc=0x1001, pc_label="StoreDamage", A=0x00),
            ],
        )

        self.assertEqual(report.findings, [])

    def test_capability_report_keeps_whole_rom_goal_incomplete(self) -> None:
        report = build_capability_report()
        statuses = {
            capability["id"]: capability["status"]
            for capability in report["capabilities"]
        }

        self.assertFalse(report["ready"])
        self.assertEqual(statuses["unified_front_door"], "complete")
        self.assertEqual(statuses["boss_ai_state_of_art"], "complete")
        self.assertEqual(statuses["damage_state_of_art"], "complete")
        self.assertEqual(statuses["whole_rom_ingest"], "complete")
        self.assertGreater(report["blocking_gap_count"], 0)
        ingest = next(capability for capability in report["capabilities"] if capability["id"] == "whole_rom_ingest")
        self.assertTrue(any("--input-log" in command for command in ingest["commands"]))
        causal = next(capability for capability in report["capabilities"] if capability["id"] == "causal_provenance")
        self.assertIn("python -m tools.debugger taint --report <minimization-or-watch-report.json>", causal["commands"])
        self.assertIn("python -m tools.debugger slice --report <minimization-or-watch-report.json>", causal["commands"])
        self.assertIn("python -m tools.debugger causal-graph --report <watch-or-taint-or-effect-report.json>", causal["commands"])
        gap_text = "\n".join(report["blocking_gaps"])
        self.assertIn("modeled checkpoint-to-writer effect-span consistency", gap_text)
        self.assertNotIn("effect replay validation", gap_text)

