    def test_investigate_can_execute_playtest_runtime_snapshots(self) -> None:
        class FakeArray:
            shape = (2, 2, 3)

            def tobytes(self) -> bytes:
                return bytes(range(12))

        class FakeScreen:
            ndarray = FakeArray()

        class FakeMemory:
            def __getitem__(self, key: Any) -> int:
                if isinstance(key, tuple):
                    bank, address = key
                    return (int(bank) * 17 + int(address)) & 0xFF
                address = int(key)
                io = {
                    0xFF26: 0x8F,
                    0xFF40: 0x93,
                    0xFF41: 0x01,
                    0xFF42: 0x12,
                    0xFF43: 0x34,
                    0xFF44: 0x56,
                    0xFF45: 0x78,
                    0xFF46: 0xC0,
                    0xFF47: 0xE4,
                    0xFF48: 0xD2,
                    0xFF49: 0x24,
                    0xFF4A: 0x08,
                    0xFF4B: 0x07,
                    0xFF4F: 0x01,
                    0xFF70: 0x02,
                }
                return io.get(address, address & 0xFF)

        class FakePyBoy:
            memory = FakeMemory()
            screen = FakeScreen()

            def load_state(self, _fh: Any) -> None:
                return None

            def tick(self, *_args: Any) -> None:
                return None

            def stop(self, *_args: Any, **_kwargs: Any) -> None:
                return None

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            rom = root / "test.gbc"
            rom.write_bytes(bytearray(0x8000))
            symbols = root / "test.sym"
            symbols.write_text(
                "00:C100 wMusicID\n"
                "00:C3A0 wTilemap\n"
                "00:CCD9 wAttrmap\n"
                "00:C4A0 wShadowOAM\n"
                "00:FFD6 hBGMapMode\n"
                "00:FFD8 hBGMapAddress\n",
                encoding="utf-8",
            )
            state = root / "bug.state"
            state.write_bytes(b"state")
            packet = build_playtest_packet(
                rom_path="test.gbc",
                symbols_path="test.sym",
                save_state="bug.state",
                watch_symbols=("wMusicID",),
                symptom="music cuts out after warp",
                packet_path="packet.json",
                root=root,
            )
            (root / "packet.json").write_text(json.dumps(packet), encoding="utf-8")
            out_dir = root / "run"

            with patch("tools.debugger.visual_snapshot.trace_runtime.open_pyboy", return_value=FakePyBoy()):
                with patch("tools.debugger.audio_snapshot.trace_runtime.open_pyboy", return_value=FakePyBoy()):
                    with patch("tools.debugger.visual_snapshot.trace_runtime.disable_realtime"):
                        with patch("tools.debugger.audio_snapshot.trace_runtime.disable_realtime"):
                            report = build_investigation_run(
                                reports=("packet.json",),
                                out_dir=str(out_dir),
                                execute_snapshots=True,
                                max_targets=6,
                                max_cases=4,
                                root=root,
                            )
            visual = json.loads((out_dir / "03_visual_snapshot.json").read_text(encoding="utf-8"))
            audio = json.loads((out_dir / "03_audio_snapshot.json").read_text(encoding="utf-8"))

        self.assertTrue(report["valid"])
        self.assertTrue(report["executed_snapshots"])
        self.assertEqual(visual["proof_status"], "runtime_observed")
        self.assertEqual(audio["proof_status"], "runtime_observed")
        self.assertTrue(any(item["kind"] == "unified_debugger_visual_snapshot" for item in report["reports"]))
        self.assertTrue(any(item["kind"] == "unified_debugger_audio_snapshot" for item in report["reports"]))
        self.assertIn("runtime_observed", {item["proof_status"] for item in report["top_findings"]})

    def test_investigate_can_execute_runtime_attribution_chain(self) -> None:
        class FakeRegisters:
            A = 0x2A
            F = 0
            B = 0
            C = 0
            D = 0
            E = 0
            H = 0xD1
            L = 0x41
            SP = 0xDFF0
            PC = 0x4000

        class FakeMemory:
            def __init__(self) -> None:
                self.values = {
                    0xD141: 0x2A,
                    0xD142: 0x00,
                }

            def __getitem__(self, key: Any) -> int:
                return self.values.get(int(key), 0)

            def __setitem__(self, key: Any, value: Any) -> None:
                self.values[int(key)] = int(value) & 0xFF

        class FakePyBoy:
            def __init__(self) -> None:
                self.register_file = FakeRegisters()
                self.memory = FakeMemory()
                self.callbacks = []

            def load_state(self, _fh: Any) -> None:
                return None

            def hook_register(self, bank: int, pc: int, callback: Any, _ctx: Any) -> None:
                self.callbacks.append((bank, pc, callback))

            def hook_deregister(self, bank: int, pc: int) -> None:
                self.callbacks = [item for item in self.callbacks if item[:2] != (bank, pc)]

            def tick(self, *_args: Any) -> None:
                for _bank, pc, callback in list(self.callbacks):
                    self.register_file.PC = pc
                    callback(None)

            def stop(self, *_args: Any, **_kwargs: Any) -> None:
                return None

        class FakeHookRegisters:
            PC = 0
            F = 0

        class FakeHookMemory:
            def __init__(self) -> None:
                self.values = {0xC200: 0}

            def __getitem__(self, key: Any) -> int:
                return self.values.get(int(key), 0)

            def __setitem__(self, key: Any, value: Any) -> None:
                self.values[int(key)] = int(value) & 0xFF

        class FakeHookPyBoy:
            def __init__(self) -> None:
                self.register_file = FakeHookRegisters()
                self.memory = FakeHookMemory()
                self.callbacks = {}
                self.sequence = [
                    (0x0159, 0x00, 0x0F),
                    (0x015A, 0x00, 0x10),
                    (0x015B, 0x00, 0x0F),
                    (0x015C, 0x10, 0x0F),
                    (0x015E, 0x00, 0x1F),
                    (0x015F, 0x80, 0x1F),
                    (0x0161, 0x00, 0x0F),
                ]

            def hook_register(self, _bank: int, pc: int, callback: Any, _ctx: Any) -> None:
                self.callbacks[pc] = callback

            def hook_deregister(self, _bank: int, pc: int) -> None:
                self.callbacks.pop(pc, None)

            def tick(self, *_args: Any) -> None:
                for pc, flags, value in self.sequence:
                    self.register_file.PC = pc
                    self.register_file.F = flags
                    self.memory[0xC200] = value
                    callback = self.callbacks.get(pc)
                    if callback:
                        callback(None)

            def stop(self, *_args: Any, **_kwargs: Any) -> None:
                return None

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            rom = bytearray(0x8000)
            rom[0x4000:0x4006] = bytes([0x3E, 0x2A, 0xEA, 0x41, 0xD1, 0xC9])
            (root / "unit.gbc").write_bytes(bytes(rom))
            (root / "test.sym").write_text(
                "01:4000 UnitFunc\n01:4006 NextFunc\n01:D141 wCurDamage\n",
                encoding="utf-8",
            )
            (root / "bug.state").write_bytes(b"state")
            packet = build_playtest_packet(
                rom_path="unit.gbc",
                symbols_path="test.sym",
                save_state="bug.state",
                symbols=("UnitFunc",),
                watch_symbols=("wCurDamage",),
                addresses=("D141",),
                symptom="damage jumps after scripted hit",
                packet_path="packet.json",
                root=root,
            )
            (root / "packet.json").write_text(json.dumps(packet), encoding="utf-8")
            out_dir = root / "run"

            with patch("tools.trace.runtime.open_pyboy", side_effect=[FakeHookPyBoy(), FakePyBoy()]):
                with patch("tools.trace.runtime.disable_realtime"):
                    report = build_investigation_run(
                        reports=("packet.json",),
                        out_dir=str(out_dir),
                        execute_attribution=True,
                        frames=1,
                        max_targets=6,
                        max_events=200,
                        max_cases=4,
                        root=root,
                    )
            instruction = json.loads((out_dir / "03_instruction_trace.json").read_text(encoding="utf-8"))
            hook_order = json.loads((out_dir / "03_hook_order_probe.json").read_text(encoding="utf-8"))
            effect = json.loads((out_dir / "03_effect_trace.json").read_text(encoding="utf-8"))
            reverse = json.loads((out_dir / "03_reverse_query.json").read_text(encoding="utf-8"))
            dynamic = json.loads((out_dir / "03_dynamic_taint.json").read_text(encoding="utf-8"))
            graph = json.loads((out_dir / "03_causal_graph.json").read_text(encoding="utf-8"))
            runtime_index = json.loads((out_dir / "03_runtime_trace_index.json").read_text(encoding="utf-8"))
            coverage = json.loads((out_dir / "05_coverage.json").read_text(encoding="utf-8"))

        report_kinds = {item["kind"] for item in report["reports"]}
        graph_node_kinds = {node["kind"] for node in graph["nodes"]}
        graph_relations = {edge["relation"] for edge in graph["edges"]}

        self.assertTrue(report["valid"])
        self.assertTrue(report["executed_attribution"])
        self.assertEqual(report["runtime_attribution"]["status"], "completed")
        self.assertTrue(report["runtime_attribution"]["hook_order_executed"])
        self.assertTrue(report["runtime_attribution"]["hook_order_passed"])
        self.assertEqual(report["runtime_attribution"]["hook_order_proof_status"], "runtime_observed")
        self.assertTrue(report["effective_runtime_traces"][0].endswith("03_instruction_trace.jsonl"))
        self.assertEqual(instruction["proof_status"], "instruction_observed")
        self.assertEqual(hook_order["kind"], "unified_debugger_hook_order_probe")
        self.assertTrue(hook_order["executed"])
        self.assertTrue(hook_order["passed"])
        self.assertEqual(hook_order["proof_status"], "runtime_observed")
        self.assertEqual(instruction["trace_output"]["record_count"], 3)
        self.assertEqual(effect["proof_status"], "instruction_observed")
        self.assertTrue(effect["hook_order_pre_state_proven"])
        self.assertEqual(effect["hook_order_proof_status"], "runtime_observed")
        self.assertEqual(effect["hook_order_validations"][0]["source"], "run/03_hook_order_probe.json")
        self.assertGreaterEqual(effect["memory_write_count"], 1)
        self.assertEqual(reverse["proof_status"], "instruction_observed")
        self.assertGreaterEqual(reverse["result_count"], 1)
        self.assertGreaterEqual(dynamic["write_attribution_count"], 1)
        self.assertGreaterEqual(graph["path_count"], 1)
        self.assertIn("hook_order_validation", graph_node_kinds)
        self.assertIn("carries_hook_order_validation", graph_relations)
        self.assertGreaterEqual(runtime_index["matched_event_count"], 1)
        self.assertEqual(coverage["trace_count"], 1)
        self.assertIn("unified_debugger_instruction_trace", report_kinds)
        self.assertIn("unified_debugger_hook_order_probe", report_kinds)
        self.assertIn("unified_debugger_effect_trace", report_kinds)
        self.assertIn("unified_debugger_reverse_query", report_kinds)
        self.assertIn("unified_debugger_dynamic_taint_report", report_kinds)
        self.assertIn("unified_debugger_causal_graph", report_kinds)
        self.assertIn("unified_debugger_trace_index", report_kinds)

