        self.assertTrue(patches[0]["verified"])
        self.assertTrue(minimized["minimized_execution_view"])
        self.assertEqual(minimized["save_state_delta"]["changed_byte_count"], 1)
        self.assertEqual(minimized["save_state_delta"]["changed_offsets"], [1])
        self.assertEqual(state_patch["minimized_save_state_delta"]["changed_byte_count"], 1)
        self.assertEqual(state_patch["minimized_save_state_delta"]["changed_offsets"], [1])
        self.assertIn("minimized_save_state_delta_changed_bytes=1", ranked_route["evidence"])
        self.assertIn("minimized_save_state_delta_offsets=1", ranked_route["evidence"])
        self.assertIn("minimized_save_state_delta_changed_bytes=1", impact_route["evidence"])
        self.assertIn("minimized_save_state_delta_offsets=1", impact_route["evidence"])
        self.assertIn("minimized_save_state_delta_changed_bytes=1", minimization_event["detail"])
        self.assertIn("minimized_save_state_delta_offsets=1", minimization_event["detail"])
        self.assertTrue(candidate_state_written)

