    def test_minimize_reruns_raw_address_watch_reducer_for_state_space_candidates(self) -> None:
        class FakeRegisterFile:
            PC = 0x4000

        class FakeMemory:
            def __init__(self) -> None:
                self.values: dict[Any, int] = {0xFF70: 1, 0xD141: 0, 0xD142: 0}

            def __getitem__(self, key: Any) -> int:
                return self.values.get(key, 0)

            def __setitem__(self, key: Any, value: int) -> None:
                self.values[key] = value & 0xFF

        class FakePyBoy:
            def __init__(self) -> None:
                self.memory = FakeMemory()
                self.register_file = FakeRegisterFile()

            def load_state(self, fh: Any) -> None:
                data = fh.read()
                self.memory = FakeMemory()
                if b"D141=2A" in data:
                    self.memory[0xD141] = 0x2A
                if b"D142=FF" in data:
                    self.memory[0xD142] = 0xFF

            def save_state(self, fh: Any) -> None:
                parts = []
                if self.memory[0xD141] == 0x2A:
                    parts.append(b"D141=2A")
                if self.memory[0xD142] == 0xFF:
                    parts.append(b"D142=FF")
                fh.write(b";".join(parts) or b"base-state")

            def tick(self, *_args: Any) -> None:
                if self.memory[0xD141] == 0x2A:
                    self.memory[0xD141] = 0x2B

            def stop(self, save: bool = False) -> None:
                return None

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.gbc").write_bytes(bytes(0x8000))
