        impact_semantic_routes = [item for item in impact["items"] if item["type"] == "semantic_reducer_route"]
        ranked_actions = "\n".join(ranked_route["next_actions"])
        impact_actions = "\n".join(impact_route["next_actions"])
        covered = {target["id"]: target for target in coverage["targets"]}
        minimization_event = next(event for event in visualization["timeline"] if event["type"] == "state_patch_minimization")
