        self.assertIn("tools.debugger provenance --report minimize.json", ranked_actions)
        self.assertIn("tools.debugger taint --report minimize.json", ranked_actions)
        self.assertIn("tools.debugger slice --report minimize.json", ranked_actions)
        self.assertTrue(any(item["title"].endswith("battle_mechanics_semantic_gates") for item in ranked_semantic_routes))
        self.assertTrue(any("tools.damage_debugger.oracle" in "\n".join(item["next_actions"]) for item in ranked_semantic_routes))
        self.assertIn("raw_damage_byte", impact_route["related_symbols"])
