    def test_minimize_executes_content_state_candidates_with_watch_rerun(self) -> None:
        class FakeRegisterFile:
            PC = 0x4000

        class FakeMemory:
            def __init__(self) -> None:
                self.values: dict[Any, int] = {0xFF70: 1}

            def __getitem__(self, key: Any) -> int:
                return self.values.get(key, 0)

            def __setitem__(self, key: Any, value: int) -> None:
                self.values[key] = value & 0xFF

        class FakePyBoy:
            def __init__(self) -> None:
                self.memory = FakeMemory()
                self.register_file = FakeRegisterFile()

            def load_state(self, fh: Any) -> None:
                data = fh.read()
                self.memory = FakeMemory()
                if b"mapgroup=24" in data:
                    self.memory[1, 0xDA00] = 0x18

            def save_state(self, fh: Any) -> None:
                if self.memory[1, 0xDA00] == 0x18:
                    fh.write(b"mapgroup=24")
                else:
                    fh.write(b"base-state")

            def tick(self, *_args: Any) -> None:
                if self.memory[1, 0xDA00] == 0x18:
                    self.memory[1, 0xDA00] = 0x19

            def stop(self, save: bool = False) -> None:
                return None

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.gbc").write_bytes(bytes(0x8000))
            (root / "base.state").write_bytes(b"base-state")
            (root / "test.sym").write_text(
                "01:4000 MapTick\n01:DA00 wMapGroup\n01:DA01 wMapNumber\n",
                encoding="utf-8",
            )
            content_state = root / "content_state.json"
            content_state.write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_content_state_materialization",
                        "valid": True,
                        "rom": "test.gbc",
                        "symbols": "test.sym",
                        "base_save_state": "base.state",
                        "executed": False,
                        "materializations": [
                            {
                                "scenario_id": "content_scenario_1_0000",
                                "precondition_kind": "map_position",
                                "source_file": "maps/UnitMap.asm",
                                "status": "ready",
                                "patches": [
                                    {
                                        "symbol": "wMapGroup",
                                        "base_symbol": "wMapGroup",
                                        "value": 24,
                                        "value_hex": "18",
                                        "bank": 1,
                                        "address": 0xDA00,
                                        "bank_address": "01:DA00",
                                    },
                                    {
                                        "symbol": "wMapNumber",
                                        "base_symbol": "wMapNumber",
                                        "value": 3,
                                        "value_hex": "03",
                                        "bank": 1,
                                        "address": 0xDA01,
                                        "bank_address": "01:DA01",
                                    },
                                ],
                            }
                        ],
                        "patch_count": 2,
                        "errors": [],
                    }
                ),
                encoding="utf-8",
            )
            out_state_report = root / "minimized_content_state.json"

            with patch("tools.trace.runtime.open_pyboy", side_effect=lambda *_args, **_kwargs: FakePyBoy()):
                report = build_minimization_plan(
                    reports=("content_state.json",),
                    expectations=("event=watch_change,symbol=wMapGroup",),
                    out_state_report="minimized_content_state.json",
                    execute_state_patches=True,
                    symbols_path="test.sym",
                    root=root,
                )
            minimized = json.loads(out_state_report.read_text(encoding="utf-8"))

        state_patch = report["state_patch_minimization"]
        patches = minimized["materializations"][0]["patches"]

        self.assertTrue(report["valid"])
        self.assertTrue(state_patch["preserved"])
        self.assertEqual(state_patch["content_state_report_count"], 1)
        self.assertGreater(state_patch["semantic_watch_rerun_attempt_count"], 0)
        self.assertGreater(state_patch["semantic_replay_rerun_attempt_count"], 0)
        self.assertEqual(state_patch["semantic_replay_rerun_attempt_count"], state_patch["semantic_replay_rerun_count"])
        self.assertEqual(state_patch["minimized_patch_count"], 1)
        self.assertEqual([patch["symbol"] for patch in patches], ["wMapGroup"])
        self.assertTrue(minimized["executed"])
        self.assertTrue(minimized["execution"]["applied_patches"][0]["applied"])
        self.assertTrue(minimized["semantic_watch_reducer"]["executed"])
        self.assertTrue(minimized["semantic_replay_reducer"]["executed"])
        self.assertEqual(minimized["semantic_replay_reducer"]["watch_symbols"], ["wMapGroup"])
        self.assertIn("maps/UnitMap.asm", minimized["semantic_replay_reducer"]["source_files"])
        self.assertEqual(minimized["replay_report"]["effective_save_state"], minimized["semantic_replay_reducer"]["save_state"])
        self.assertIn("maps/UnitMap.asm", minimized["replay_report"]["changed_files"])
        self.assertIn("maps/UnitMap.asm", minimized["replay_report"]["replay_targets"]["source_files"])
        self.assertEqual(minimized["watch_report"]["hit_count"], 1)

