    def test_taint_and_slice_derive_inputs_from_state_patch_minimization_report(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "ram").mkdir()
            (root / "engine").mkdir()
            symbols = root / "test.sym"
            symbols.write_text(
                "01:D141 wCurDamage\n01:D142 wBattleMonAttack\n01:4000 BattleCommand_Test\n",
                encoding="utf-8",
            )
            (root / "ram" / "wram.asm").write_text(
                "wCurDamage:: ds 2\nwBattleMonAttack:: ds 2\n",
                encoding="utf-8",
            )
            (root / "engine" / "battle.asm").write_text(
                "BattleCommand_Test:\n\tld a, [wBattleMonAttack]\n\tld [wCurDamage], a\n\tret\n",
                encoding="utf-8",
            )
            minimize_report = {
                "kind": "unified_debugger_minimization_plan",
                "valid": True,
                "state_patch_minimization": {
                    "attempted": True,
                    "preserved": True,
                    "source_files": ["engine/battle.asm"],
                    "source_symbols": ["BattleCommand_Test"],
                    "source_mems": ["D141=wCurDamage"],
                    "results": [
                        {
                            "semantic_watch_symbols": ["wCurDamage"],
                        }
                    ],
                },
            }
            (root / "minimize.json").write_text(json.dumps(minimize_report), encoding="utf-8")

            taint = build_taint_report(
                reports=("minimize.json",),
                symbols_path="test.sym",
                root=root,
            )
            slice_report = build_slice_report(
                reports=("minimize.json",),
                symbols_path="test.sym",
                root=root,
            )

            cli_minimize_report = dict(minimize_report)
            cli_minimize_report["state_patch_minimization"] = {
                **minimize_report["state_patch_minimization"],
                "source_files": [str(root / "engine" / "battle.asm")],
            }
            (root / "cli_minimize.json").write_text(json.dumps(cli_minimize_report), encoding="utf-8")
            taint_out = root / "taint.json"
            slice_out = root / "slice.json"
            with redirect_stdout(io.StringIO()):
                taint_code = debugger_main(
                    [
                        "taint",
                        "--symbols",
                        str(symbols),
                        "--report",
                        str(root / "cli_minimize.json"),
                        "--json-out",
                        str(taint_out),
                    ]
                )
                slice_code = debugger_main(
                    [
                        "slice",
                        "--symbols",
                        str(symbols),
                        "--report",
                        str(root / "cli_minimize.json"),
                        "--json-out",
                        str(slice_out),
                    ]
                )

            taint_cli = json.loads(taint_out.read_text(encoding="utf-8"))
            slice_cli = json.loads(slice_out.read_text(encoding="utf-8"))

        taint_targets = {target["symbol"]: target for target in taint["targets"]}
        slice_targets = {target["query"]: target for target in slice_report["targets"]}
        taint_contributors = {
            item["symbol"] for item in taint_targets["wCurDamage"]["contributors"]
        }
        slice_sources = {edge["source"] for edge in slice_targets["wCurDamage"]["incoming"]}

        self.assertTrue(taint["valid"])
        self.assertEqual(taint["input_reports"], ["minimize.json"])
        self.assertEqual(taint["input_symbols"], [])
        self.assertIn("BattleCommand_Test", taint["derived_report_symbols"])
        self.assertIn("wCurDamage", taint["derived_report_symbols"])
        self.assertIn("engine/battle.asm", taint["derived_report_source_files"])
        self.assertEqual(taint_targets["wCurDamage"]["sink_count"], 1)
        self.assertIn("wBattleMonAttack", taint_contributors)

        self.assertTrue(slice_report["valid"])
        self.assertEqual(slice_report["input_reports"], ["minimize.json"])
        self.assertIn("BattleCommand_Test", slice_report["derived_report_symbols"])
        self.assertIn("wCurDamage", slice_report["derived_report_symbols"])
        self.assertIn("engine/battle.asm", slice_report["derived_report_source_files"])
        self.assertTrue(slice_targets["wCurDamage"]["found"])
        self.assertIn("BattleCommand_Test", slice_sources)

        self.assertEqual(taint_code, 0)
        self.assertEqual(slice_code, 0)
        self.assertEqual(taint_cli["target_count"], 2)
        self.assertEqual(slice_cli["targets"][0]["query"], "BattleCommand_Test")

