    def test_evidence_atoms_flow_from_dynamic_taint_to_rank_and_impact(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                json.dumps(
                    {
                        "seq": 0,
                        "bank": 1,
                        "pc": 0x4000,
                        "pc_label": "UnitFunc",
                        "opcode": 0x34,
                        "regs": {"HL": 0xC200},
                        "watch_values": {"$C200": "0F"},
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            dynamic = build_dynamic_taint_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                source_mems=("C200=seed_byte",),
                sink_addresses=("C200",),
                root=root,
            )
            (root / "dynamic_taint.json").write_text(json.dumps(dynamic), encoding="utf-8")
            ranked = rank_findings(reports=("dynamic_taint.json",), root=root)
            impact = build_impact_report(reports=("dynamic_taint.json",), root=root)

        path = dynamic["paths"][0]
        attribution = dynamic["write_attributions"][0]
        ranked_taint = next(item for item in ranked["findings"] if item["type"] == "taint_path")
        ranked_write = next(item for item in ranked["findings"] if item["type"] == "reverse_attribution")
        impact_taint = next(item for item in impact["items"] if item["type"] == "taint_path")
        impact_write = next(item for item in impact["items"] if item["type"] == "reverse_attribution")

        self.assertEqual(path["evidence_atoms"][0]["claim_type"], "dynamic_taint.path")
        self.assertEqual(path["evidence_atoms"][0]["proof_status"], "taint_proven")
        self.assertEqual(attribution["evidence_atoms"][0]["claim_type"], "dynamic_taint.write_attribution")
        self.assertEqual(attribution["evidence_atoms"][0]["proof_status"], "instruction_observed")
        self.assertTrue(any(atom["claim_type"] == "dynamic_taint.path" for atom in ranked_taint["evidence_atoms"]))
        self.assertTrue(any(atom["claim_type"] == "dynamic_taint.write_attribution" for atom in ranked_write["evidence_atoms"]))
        self.assertTrue(any(atom["claim_type"] == "dynamic_taint.path" for atom in impact_taint["evidence_atoms"]))
        self.assertTrue(any(atom["claim_type"] == "dynamic_taint.write_attribution" for atom in impact_write["evidence_atoms"]))

