        self.assertEqual(high_write["value_hex"], "10")
        self.assertEqual(high_operand["register_provenance"]["operation"], "add hl, bc")
        self.assertEqual(high_operand["register_provenance"]["taint"], ["seed_pair"])
        self.assertEqual(high_write["taint"], ["seed_pair"])
        self.assertEqual(dynamic["path_count"], 2)
        self.assertEqual(
            {path["target"]: path["taint"] for path in dynamic["paths"]},
            {"$C1FE": ["seed_pair"], "$C1FF": ["seed_pair"]},
        )
        self.assertEqual(
            {path["target"]: path["contributors"][0]["symbol"] for path in dynamic["paths"]},
            {"$C1FE": "seed_pair", "$C1FF": "seed_pair"},
        )
        self.assertEqual(paths["$C1FE"]["source_kind"], "instruction_trace_write_attribution")
        self.assertEqual(paths["$C1FE"]["evidence_source_proof_status"], "instruction_observed")
        self.assertIn("register_provenance=l@01:4000", "\n".join(paths["$C1FE"]["evidence"]))
        graph_evidence = "\n".join(
            str(evidence)
            for edge in graph["edges"]
            for evidence in edge.get("evidence", [])
        )
        self.assertIn("register_provenance=l@01:4000", graph_evidence)

