    def test_dynamic_taint_public_engine_finding_preserves_bank_unverified_match_proof(self) -> None:
        class Finding:
            seq = 0
            pc = 0x4000
            pc_label = "BankedWriter"
            mnemonic = "ld [nn], a"
            sink = "wCurDamage"
            address = 0xD141
            taint = ["move_power"]

        finding = public_finding(
            Finding(),
            source="instruction_trace.jsonl",
            match={
                "address_key": "wramx:02:D141",
                "match_precision": "bus_address_unverified_bank",
                "bank_match": "bus_address_unverified_bank",
                "bank_source": "bank_state.wram",
                "proof_downgrade_reason": "unbanked sink matched a bank-qualified runtime key by bus address",
            },
        )
        paths = build_paths(
            findings=[finding],
            sinks=[DamageSink("wCurDamage", 0xD141, 2)],
            register_sources={"a": "move_power"},
            source_memory={},
            max_paths=10,
        )

        self.assertEqual(finding["source_kind"], "instruction_trace_taint_engine")
        self.assertEqual(finding["proof_status"], "planned_only")
        self.assertEqual(finding["address_key"], "wramx:02:D141")
        self.assertEqual(finding["match_precision"], "bus_address_unverified_bank")
        self.assertEqual(finding["bank_match"], "bus_address_unverified_bank")
        self.assertIn("match_precision=bus_address_unverified_bank", finding["evidence"])
        self.assertEqual(paths[0]["proof_status"], "planned_only")
        self.assertEqual(paths[0]["evidence_source_proof_status"], "planned_only")
        self.assertIn("proof_downgrade_reason=unbanked sink matched a bank-qualified runtime key by bus address", paths[0]["evidence"])

