        self.assertEqual(write_index["FF12"]["last_writer_seq"], 2)
        self.assertEqual(write_index["FF12"]["history"][-1]["evidence_source"], "modeled_from_instruction_frame")
        self.assertEqual(write_index["FF12"]["history"][-1]["value_hex"], "77")
        self.assertEqual(write_index["FF46"]["last_writer_seq"], 4)
        self.assertEqual(write_index["FE00"]["last_writer_seq"], 4)
        self.assertEqual(write_index["C000"]["read_count"], 1)
        side_effects = {item["kind"]: item for item in report["side_effect_index"]}
        self.assertEqual(side_effects["oam_dma_trigger"]["triggers"][0]["source_range"], "C000-C09F")
        self.assertEqual(side_effects["mbc_rom_bank_select"]["last_pc"], "01:400B")
        self.assertTrue(report["output"]["written"])
        self.assertTrue(effects_file_written)
        self.assertEqual(finding["proof_status"], "instruction_observed")
        self.assertIn("hardware_side_effects=3", finding["evidence"])
        self.assertIn("dma_copy_writes=160", finding["evidence"])
        self.assertTrue(any("side_effect oam_dma_trigger" in item for item in finding["evidence"]))
        self.assertIn("D141", finding["related_addresses"])
        self.assertTrue(reverse["valid"])
        self.assertEqual(reverse_result["last_writer_pc"], "01:4009")
        self.assertEqual(reverse_result["last_writer"]["kind"], "dma_write")
        self.assertEqual(reverse_result["last_writer"]["operation"], "OAM DMA OAM write")
        self.assertEqual(reverse_result["last_writer"]["evidence_source"], "modeled_from_oam_dma_trigger")
        self.assertEqual(reverse_result["validation"]["effect_evidence_source"], "modeled_from_oam_dma_trigger")

