        self.assertEqual(rst_stack_values, ["09", "40"])
        self.assertEqual(push_stack_values, ["D0", "AB"])
        self.assertEqual(control_ops, ["call", "return", "rst"])
        self.assertFalse(any(item.get("kind") == "stack_write" for item in effects_by_seq[1]))
        self.assertFalse(any(item.get("operation") == "call" for item in effects_by_seq[1]))
        self.assertFalse(any(item.get("kind") == "stack_read" for item in effects_by_seq[3]))
        self.assertFalse(any(item.get("operation") == "return" for item in effects_by_seq[3]))
        self.assertEqual(reverse_by_address["C0FE"]["last_writer"]["operation"], "call return low")
        self.assertEqual(reverse_by_address["C1FE"]["last_writer"]["operation"], "rst return low")
        self.assertEqual(reverse_by_address["C2FE"]["last_writer"]["operation"], "push af low")

