    def test_shared_sm83_model_dynamic_taint_and_effect_trace_parity_stack_control(self) -> None:
        from tools.debugger.sm83_model import SM83_MODEL_SOURCE, stack_control_semantics

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                "\n".join(
                    json.dumps(record)
                    for record in [
                        {
                            "seq": 0,
                            "bank": 1,
                            "pc": 0x4000,
                            "pc_label": "PushBC",
                            "opcode": 0xC5,
                            "regs": {"B": 0x12, "C": 0x34, "SP": 0xC100},
                        },
                        {
                            "seq": 1,
                            "bank": 1,
                            "pc": 0x4001,
                            "pc_label": "Call",
                            "opcode": 0xCD,
                            "operand": [0x00, 0x50],
                            "regs": {"SP": 0xC200},
                        },
                        {
                            "seq": 2,
                            "bank": 1,
                            "pc": 0x4004,
                            "pc_label": "PopBC",
                            "opcode": 0xC1,
                            "regs": {"SP": 0xC300},
                            "watch_values": {"$C300": "7856"},
                        },
                        {
                            "seq": 3,
                            "bank": 1,
                            "pc": 0x4005,
                            "pc_label": "Ret",
                            "opcode": 0xC9,
                            "regs": {"SP": 0xC400},
                            "watch_values": {"$C400": "ABCD"},
                        },
                        {
                            "seq": 4,
                            "bank": 1,
                            "pc": 0x4006,
                            "pc_label": "Rst",
                            "opcode": 0xDF,
                            "regs": {"SP": 0xC500},
                        },
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("C0FE", "C1FE", "C300", "C400", "C4FE"),
                root=root,
            )
            dynamic = build_dynamic_taint_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                sink_addresses=("C0FE", "C1FE", "C4FE"),
                root=root,
            )

        call_model = stack_control_semantics(0xCD)
        effect_stack_items = [
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("kind") in {"stack_write", "stack_read"}
        ]
        effect_sp_writes = [
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("access") == "register_write" and item.get("register") == "SP"
        ]
        effect_control = [
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("kind") == "control_flow"
        ]
        dynamic_stack_writes = [
            item
            for item in dynamic["write_attributions"]
            if item.get("write_kind") in {"push bc low", "call return low", "rst return low"}
        ]

        self.assertEqual(call_model.stack_write_operation, "call return")
        self.assertEqual(call_model.sp_write_operation, "call updates sp")
        self.assertEqual(call_model.control_operation, "call")
        self.assertEqual(call_model.updated_sp(0xC200), 0xC1FE)
        self.assertTrue(effect["valid"])
        self.assertTrue(dynamic["valid"])
        self.assertEqual(
            [item["operation"] for item in effect_sp_writes],
            ["push bc updates sp", "call updates sp", "pop bc updates sp", "ret updates sp", "rst updates sp"],
        )
        self.assertEqual([item["value_hex"] for item in effect_sp_writes], ["C0FE", "C1FE", "C302", "C402", "C4FE"])
        self.assertEqual([item["operation"] for item in effect_control], ["call", "return", "rst"])
        self.assertTrue(effect_stack_items)
        self.assertTrue(dynamic_stack_writes)
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in effect_stack_items))
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in effect_sp_writes))
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in effect_control))
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in dynamic_stack_writes))

    def test_shared_sm83_pop_af_masks_flag_low_nibble_for_effect_and_dynamic_taint(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                "\n".join(
                    json.dumps(record)
                    for record in [
                        {
                            "seq": 0,
                            "bank": 1,
                            "pc": 0x4000,
                            "pc_label": "PopAF",
                            "opcode": 0xF1,
                            "regs": {"SP": 0xC100},
                            "watch_values": {"$C100": "FF12"},
                        },
                        {
                            "seq": 1,
                            "bank": 1,
                            "pc": 0x4001,
                            "pc_label": "PushAF",
                            "opcode": 0xF5,
                            "regs": {"A": 0x12, "F": 0xF0, "SP": 0xC200},
                        },
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("C100", "C1FE"),
                root=root,
            )
            (root / "effect_trace.json").write_text(json.dumps(effect), encoding="utf-8")
            dynamic_from_trace = build_dynamic_taint_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                source_mems=("C100=flag_stack_byte",),
                sink_addresses=("C1FE",),
                root=root,
            )
            dynamic_from_effect = build_dynamic_taint_report(
                reports=("effect_trace.json",),
                symbols_path="test.sym",
                source_mems=("C100=flag_stack_byte",),
                sink_addresses=("C1FE",),
                root=root,
            )

        pop_af_write = next(
            item
            for item in effect["events"][0]["effects"]
            if item.get("access") == "register_write" and item.get("register") == "AF"
        )
        trace_push = dynamic_from_trace["write_attributions"][0]
        effect_push = dynamic_from_effect["write_attributions"][0]

        self.assertTrue(effect["valid"])
        self.assertEqual(pop_af_write["operation"], "pop af")
        self.assertEqual(pop_af_write["source_operands"][0]["value"], "FF")
        self.assertEqual(pop_af_write["value_hex"], "12F0")
        for attribution in (trace_push, effect_push):
            flag_operand = next(
                operand
                for operand in attribution["source_operands"]
                if operand.get("kind") == "register" and operand.get("name") == "f"
            )
            self.assertEqual(attribution["value_hex"], "F0")
            self.assertEqual(flag_operand["register_provenance"]["operation"], "pop af low")
            self.assertEqual(flag_operand["register_provenance"]["value_hex"], "F0")
            self.assertEqual(attribution["contributors"][0]["symbol"], "flag_stack_byte")

