        self.assertEqual(
            [(item["operation"], item["value_hex"], item["value_source"]) for item in flag_writes],
            [
                ("inc b flags", "30", "modeled_from_pre_register"),
                ("dec c flags", "70", "modeled_from_pre_register"),
                ("inc [hl] flags", "B0", "modeled_from_observed_memory_snapshot"),
                ("dec [hl] flags", "70", "modeled_from_observed_memory_snapshot"),
            ],
        )
        self.assertEqual([item.get("post_register_status", "") for item in register_writes], ["matched"] * 6)
        self.assertEqual([item["value_hex"] for item in memory_writes], ["00", "FF"])
        self.assertEqual([item["post_value_status"] for item in memory_writes], ["matched", "matched"])
        self.assertEqual(report["register_write_count"], 6)
        self.assertEqual(report["post_register_match_count"], 6)
        self.assertEqual(report["post_value_match_count"], 2)
        self.assertTrue(graph["valid"])
        self.assertIn("operation=inc b flags", graph_evidence)
        self.assertIn("operation=dec [hl] flags", graph_evidence)

