    def test_shared_sm83_model_dynamic_taint_and_effect_trace_parity_alu_flags(self) -> None:
        from tools.debugger.sm83_model import SM83_MODEL_SOURCE, alu_semantics

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                "\n".join(
                    json.dumps(record)
                    for record in [
                        {
                            "seq": 0,
                            "bank": 1,
                            "pc": 0x4000,
                            "pc_label": "AddB",
                            "opcode": 0x80,
                            "regs": {"A": 0x0F, "B": 0x01, "F": 0x00, "SP": 0xDFF0},
                        },
                        {
                            "seq": 1,
                            "bank": 1,
                            "pc": 0x4001,
                            "pc_label": "StoreA",
                            "opcode": 0xEA,
                            "operand": [0x41, 0xD1],
                            "regs": {"A": 0x10, "B": 0x01, "F": 0x20, "SP": 0xDFF0},
                        },
                        {
                            "seq": 2,
                            "bank": 1,
                            "pc": 0x4004,
                            "pc_label": "CpB",
                            "opcode": 0xB8,
                            "regs": {"A": 0x10, "B": 0x10, "F": 0x20, "SP": 0xDFF0},
                        },
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("D141",),
                root=root,
            )
            dynamic = build_dynamic_taint_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                source_regs=("b=operand_b",),
                sink_addresses=("D141",),
                root=root,
            )

        add_model = alu_semantics(0x80)
        cp_model = alu_semantics(0xB8)
        effect_alu_writes = [
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("operation") in {"add a, b", "add a, b flags", "cp a, b flags"}
        ]
        attribution = dynamic["write_attributions"][0]

        self.assertEqual(add_model.operation("b"), "add a, b")
        self.assertEqual(add_model.result(a=0x0F, source=0x01, flags=0x00), 0x10)
        self.assertEqual(add_model.flags(a=0x0F, source=0x01, flags=0x00), 0x20)
        self.assertEqual(cp_model.result(a=0x10, source=0x10, flags=0x20), None)
        self.assertEqual(cp_model.flags(a=0x10, source=0x10, flags=0x20), 0xC0)
        self.assertTrue(effect["valid"])
        self.assertTrue(dynamic["valid"])
        self.assertEqual(
            [(item["operation"], item["register"], item["value_hex"]) for item in effect_alu_writes],
            [("add a, b", "A", "10"), ("add a, b flags", "F", "20"), ("cp a, b flags", "F", "C0")],
        )
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in effect_alu_writes))
        self.assertEqual(attribution["register_provenance"][0]["operation"], "add a, b")
        self.assertEqual(attribution["register_provenance"][0]["model_source"], SM83_MODEL_SOURCE)
        self.assertIn("operand_b", attribution["taint"])

    def test_shared_sm83_model_dynamic_taint_and_effect_trace_parity_cb_ops(self) -> None:
        from tools.debugger.sm83_model import SM83_MODEL_SOURCE, cb_semantics

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                "\n".join(
                    json.dumps(record)
                    for record in [
                        {
                            "seq": 0,
                            "bank": 1,
                            "pc": 0x4000,
                            "pc_label": "RlB",
                            "opcode": 0xCB,
                            "operand": [0x10],
                            "regs": {"B": 0x7F, "F": 0x10},
                        },
                        {
                            "seq": 1,
                            "bank": 1,
                            "pc": 0x4002,
                            "pc_label": "StoreB",
                            "opcode": 0x70,
                            "regs": {"HL": 0xD141, "B": 0xFF},
                        },
                        {
                            "seq": 2,
                            "bank": 1,
                            "pc": 0x4003,
                            "pc_label": "BitHL",
                            "opcode": 0xCB,
                            "operand": [0x46],
                            "regs": {"HL": 0xC200, "F": 0x10},
                            "watch_values": {"$C200": "01"},
                        },
                        {
                            "seq": 3,
                            "bank": 1,
                            "pc": 0x4005,
                            "pc_label": "SetHL",
                            "opcode": 0xCB,
                            "operand": [0xC6],
                            "regs": {"HL": 0xC201, "F": 0x00},
                            "watch_values": {"$C201": "80"},
                        },
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("C200", "C201", "D141"),
                root=root,
            )
            dynamic = build_dynamic_taint_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                source_regs=("b=seed_b",),
                sink_addresses=("C201", "D141"),
                root=root,
            )

        rl_model = cb_semantics(0x10)
        bit_hl_model = cb_semantics(0x46)
        set_hl_model = cb_semantics(0xC6)
        effect_cb_items = [
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("operation") in {"rl b", "rl b flags", "bit 0, [hl]", "bit 0, [hl] flags", "set 0, [hl]"}
        ]
        effect_writes = [
            item
            for item in effect_cb_items
            if item.get("access") in {"register_write", "write"}
        ]
        store_attribution = next(item for item in dynamic["write_attributions"] if item["address"] == "D141")
        set_attribution = next(item for item in dynamic["write_attributions"] if item["address"] == "C201")
        store_provenance = {
            (item["operation"], item.get("model_source"))
            for item in store_attribution["register_provenance"]
        }

        self.assertEqual(rl_model.operation("b"), "rl b")
        self.assertEqual(rl_model.result(0x7F, flags=0x10), 0xFF)
        self.assertEqual(rl_model.flags(0x7F, flags=0x10), 0x00)
        self.assertEqual(bit_hl_model.operation("[hl]"), "bit 0, [hl]")
        self.assertIsNone(bit_hl_model.result(0x01, flags=0x10))
        self.assertEqual(bit_hl_model.flags(0x01, flags=0x10), 0x30)
        self.assertEqual(set_hl_model.operation("[hl]"), "set 0, [hl]")
        self.assertEqual(set_hl_model.result(0x80, flags=0x00), 0x81)
        self.assertTrue(effect["valid"])
        self.assertTrue(dynamic["valid"])
        self.assertEqual(
            [(item["operation"], item.get("value_hex")) for item in effect_writes],
            [("rl b", "FF"), ("rl b flags", "00"), ("bit 0, [hl] flags", "30"), ("set 0, [hl]", "81")],
        )
        self.assertTrue(effect_cb_items)
        self.assertTrue(all(item.get("model_source") == SM83_MODEL_SOURCE for item in effect_cb_items))
        self.assertIn(("rl b", SM83_MODEL_SOURCE), store_provenance)
        self.assertIn("seed_b", store_attribution["taint"])
        self.assertEqual(set_attribution["write_kind"], "set 0, [hl]")
        self.assertEqual(set_attribution["value_hex"], "81")
        self.assertEqual(set_attribution["model_source"], SM83_MODEL_SOURCE)

    def test_shared_sm83_model_effect_trace_cpu_state_and_interrupt_entry(self) -> None:
        from tools.debugger.sm83_model import SM83_MODEL_SOURCE, cpu_state_semantics, interrupt_entry_semantics

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("00:0050 Timer\n01:4000 MainLoop\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                "\n".join(
                    json.dumps(record)
                    for record in [
                        {
                            "seq": 0,
                            "bank": 1,
                            "pc": 0x4000,
                            "pc_label": "MainLoop",
                            "opcode": 0x00,
                            "regs": {"SP": 0xC100, "F": 0x00},
                        },
                        {
                            "seq": 1,
                            "bank": 0,
                            "pc": 0x0050,
                            "pc_label": "Timer",
                            "opcode": 0xD9,
                            "regs": {"SP": 0xC0FE, "F": 0x00},
                        },
                        {
                            "seq": 2,
                            "bank": 1,
                            "pc": 0x4002,
                            "pc_label": "EnableInterrupts",
                            "opcode": 0xFB,
                            "regs": {"SP": 0xC100, "F": 0x00},
                        },
                        {
                            "seq": 3,
                            "bank": 1,
                            "pc": 0x4003,
                            "pc_label": "DisableInterrupts",
                            "opcode": 0xF3,
                            "regs": {"SP": 0xC100, "F": 0x00},
                        },
                        {
                            "seq": 4,
                            "bank": 1,
                            "pc": 0x4004,
                            "pc_label": "HaltLoop",
                            "opcode": 0x76,
                            "regs": {"SP": 0xC100, "F": 0x00},
                        },
                        {
                            "seq": 5,
                            "bank": 1,
                            "pc": 0x4005,
                            "pc_label": "StopHandler",
                            "opcode": 0x10,
                            "operand": [0x00],
                            "regs": {"SP": 0xC100, "F": 0x00},
                        },
                    ]
                )
                + "\n",
                encoding="utf-8",
            )

            report = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("C0FE",),
                watch_size=2,
                root=root,
            )

        interrupt_model = interrupt_entry_semantics(0x50)
        reti_model = cpu_state_semantics(0xD9)
        halt_model = cpu_state_semantics(0x76)
        stop_model = cpu_state_semantics(0x10)
        shared_effects = [
            item
            for event in report["events"]
            for item in event["effects"]
            if item.get("kind") in {"interrupt_entry", "ime", "cpu_state"}
            or item.get("operation") in {"interrupt entry updates sp", "interrupt return low", "interrupt return high"}
        ]
        side_effect_triggers = [
            trigger
            for item in report["side_effect_index"]
            for trigger in item.get("triggers", [])
            if trigger.get("operation") in {"timer interrupt entry", "reti", "ei", "di", "halt", "stop"}
        ]

        self.assertEqual(interrupt_model.name, "timer")
        self.assertEqual(interrupt_model.operation, "timer interrupt entry")
        self.assertEqual(interrupt_model.updated_sp(0xC100), 0xC0FE)
        self.assertEqual(interrupt_model.return_address(0x4000, 1), 0x4001)
        self.assertEqual(reti_model.operation, "reti")
        self.assertEqual(halt_model.mode, "halted")
        self.assertEqual(stop_model.mode, "stopped")
        self.assertTrue(report["valid"])
        self.assertEqual(report["interrupt_entry_count"], 1)
        self.assertEqual(
            [(item["kind"], item["operation"]) for item in shared_effects],
            [
                ("interrupt_entry", "timer interrupt entry"),
                ("register_write", "interrupt entry updates sp"),
                ("stack_write", "interrupt return low"),
                ("stack_write", "interrupt return high"),
                ("ime", "reti"),
                ("ime", "ei"),
                ("ime", "di"),
                ("cpu_state", "halt"),
                ("cpu_state", "stop"),
            ],
        )
