        self.assertEqual(dynamic_unmodeled["operation"], "ld [hl], a")
        self.assertEqual(dynamic_unmodeled["missing_registers"], ["HL"])
        self.assertEqual(dynamic_unmodeled["proof_status"], "instruction_observed")
        self.assertEqual(dynamic_unmodeled["target_match_proof_status"], "planned_only")
        self.assertEqual(dynamic_unmodeled["attribution_status"], "unresolved_missing_register")
        self.assertEqual(dynamic["write_attribution_count"], 0)
