        self.assertEqual(history_by_address["C200"][0]["value_hex"], "77")
        self.assertEqual(history_by_address["FF12"][0]["value_hex"], "88")
        self.assertEqual(history_by_address["C100"][0]["value_hex"], "34")
        self.assertEqual(history_by_address["C101"][0]["value_hex"], "40")

