    def test_effect_trace_banked_symbol_watch_requires_runtime_bank_match(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text(
                "01:4000 UnitFunc\n"
                "02:D141 BankedDamage\n"
                "01:D141 WrongBankDamage\n",
                encoding="utf-8",
            )
            banked_record = {
                "seq": 0,
                "bank": 1,
                "pc": 0x4000,
                "pc_label": "UnitFunc",
                "opcode": 0xEA,
                "operand": [0x41, 0xD1],
                "regs": {"A": 0x2A, "SP": 0xDFF0},
                "bank_state": {"wram": 2, "wram_raw": 0xF2},
            }
            (root / "banked_trace.jsonl").write_text(json.dumps(banked_record) + "\n", encoding="utf-8")
            unbanked_record = dict(banked_record)
            unbanked_record.pop("bank_state")
            (root / "unbanked_trace.jsonl").write_text(json.dumps(unbanked_record) + "\n", encoding="utf-8")

            precise = build_effect_trace_report(
                traces=("banked_trace.jsonl",),
                symbols_path="test.sym",
                watch_symbols=("BankedDamage", "WrongBankDamage"),
                root=root,
            )
            fallback = build_effect_trace_report(
                traces=("unbanked_trace.jsonl",),
                symbols_path="test.sym",
                watch_symbols=("WrongBankDamage",),
                root=root,
            )
            (root / "fallback_effect.json").write_text(json.dumps(fallback), encoding="utf-8")
            fallback_graph = build_causal_graph_report(reports=("fallback_effect.json",), root=root)
            fallback_ranked = rank_findings(reports=("fallback_effect.json",), root=root)
            fallback_impact = build_impact_report(reports=("fallback_effect.json",), root=root)
            fallback_visualization = build_visualization_report(reports=("fallback_effect.json",), root=root)

        precise_hits = [
            hit
            for event in precise["events"]
            for hit in event["watch_hits"]
            if hit["access"] == "write"
        ]
        fallback_hits = [
            hit
            for event in fallback["events"]
            for hit in event["watch_hits"]
            if hit["access"] == "write"
        ]
        fallback_graph_relations = {edge["relation"] for edge in fallback_graph["edges"]}
        fallback_graph_evidence = {
            evidence
            for edge in fallback_graph["edges"]
            for evidence in edge.get("evidence", [])
        }
        fallback_effect_finding = next(item for item in fallback_ranked["findings"] if item["type"] == "effect_trace_observed")
        fallback_effect_item = next(item for item in fallback_impact["items"] if item["type"] == "effect_trace_observed")
        fallback_timeline = next(
            item
            for item in fallback_visualization["timeline"]
            if item["type"] == "effect_watch_hit"
        )

        self.assertTrue(precise["valid"])
        self.assertEqual([hit["watch"] for hit in precise_hits], ["BankedDamage"])
        self.assertEqual(precise_hits[0]["bank_source"], "bank_state.wram")
        self.assertEqual(precise_hits[0]["bank_match"], "exact")
        self.assertEqual(precise_hits[0]["match_precision"], "exact_address_key")
        self.assertEqual(precise_hits[0]["target_match_proof_status"], "instruction_observed")
        self.assertEqual(precise["watch_bank_match_counts"]["exact"], 1)
        self.assertEqual(precise["bank_unverified_watch_hit_count"], 0)
        self.assertTrue(fallback["valid"])
        self.assertEqual([hit["watch"] for hit in fallback_hits], ["WrongBankDamage"])
        self.assertEqual(fallback_hits[0]["bank_match"], "bus_address_unverified_bank")
        self.assertEqual(fallback_hits[0]["match_precision"], "bus_address_unverified_bank")
        self.assertEqual(fallback_hits[0]["target_match_proof_status"], "planned_only")
        self.assertEqual(
            fallback_hits[0]["proof_downgrade_reason"],
            "bank-qualified watch matched effect by bus address without runtime bank state",
        )
        self.assertEqual(fallback_hits[0]["bank_source"], "")
        self.assertEqual(fallback["watch_bank_match_counts"]["bus_address_unverified_bank"], 1)
        self.assertEqual(fallback["bank_unverified_watch_hit_count"], 1)
        self.assertTrue(fallback_graph["valid"])
        self.assertIn("matches_watch_unverified_bank", fallback_graph_relations)
        self.assertIn("bank_match=bus_address_unverified_bank", fallback_graph_evidence)
        self.assertIn("bank_unverified_watch_hits=1", fallback_effect_finding["evidence"])
        self.assertIn("effect_proof_status=instruction_observed", fallback_effect_finding["evidence"])
        self.assertIn("target_match_proof_status=planned_only", fallback_effect_finding["evidence"])
        self.assertEqual(fallback_effect_finding["proof_status"], "planned_only")
        self.assertIn("bank_match=bus_address_unverified_bank", "\n".join(fallback_effect_finding["evidence"]))
        self.assertEqual(fallback_effect_item["proof_status"], "planned_only")
        self.assertIn("target_match_proof_status=planned_only", fallback_effect_item["evidence"])
        self.assertEqual(fallback_timeline["type"], "effect_watch_hit")
        self.assertIn("bank_match=bus_address_unverified_bank", fallback_timeline["detail"])

