        self.assertEqual(writes_by_address["8000"]["space"], "vram")
        self.assertEqual(writes_by_address["8000"]["address_key"], "vram:01:8000")
        self.assertIn("wramx:02:D141", write_index)
        self.assertIn("vram:01:8000", write_index)
        self.assertIn("02:$D141", hit_watches)
        self.assertIn("01:$8000", hit_watches)
        self.assertTrue(reverse["valid"])
        self.assertEqual(reverse["results"][0]["matched_address_key"], "wramx:02:D141")
        self.assertTrue(dynamic["valid"])
        wramx_attribution = next(
            item
            for item in dynamic["write_attributions"]
            if item.get("address_key") == "wramx:02:D141"
        )
        self.assertGreaterEqual(dynamic["write_attribution_count"], 1)
        self.assertEqual(wramx_attribution["address"], "D141")

