    def test_evidence_atoms_wrap_effect_reverse_and_causal_graph_claims(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                json.dumps(
                    {
                        "seq": 0,
                        "bank": 1,
                        "pc": 0x4000,
                        "pc_label": "UnitFunc",
                        "opcode": 0x34,
                        "regs": {"HL": 0xC200},
                        "watch_values": {"$C200": "0F"},
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                watch_addresses=("C200",),
                root=root,
            )
            (root / "effect_trace.json").write_text(json.dumps(effect), encoding="utf-8")
            reverse = build_reverse_query_report(
                reports=("effect_trace.json",),
                addresses=("C200",),
                symbols_path="test.sym",
                root=root,
            )
            (root / "reverse_query.json").write_text(json.dumps(reverse), encoding="utf-8")
            graph = build_causal_graph_report(reports=("reverse_query.json",), root=root)

        write = next(
            item
            for event in effect["events"]
            for item in event["effects"]
            if item.get("kind") == "memory_write" and item.get("address_hex") == "C200"
        )
        effect_atom = write["evidence_atoms"][0]
        result = reverse["results"][0]
        reverse_atom = result["evidence_atoms"][0]
        graph_edge = next(edge for edge in graph["edges"] if edge["relation"] == "answers_last_write")

        self.assertEqual(effect_atom["claim_type"], "effect.memory_write")
        self.assertEqual(effect_atom["origin"], "effect_trace")
        self.assertEqual(effect_atom["observation_type"], "instruction_frame")
        self.assertEqual(effect_atom["proof_status"], "instruction_observed")
        self.assertEqual(effect_atom["scope"]["seq"], 0)
        self.assertEqual(effect_atom["scope"]["pc_label"], "UnitFunc")
        self.assertIn("C200", effect_atom["subjects"]["addresses"])
        self.assertEqual(effect_atom["validation"]["pre_state_proof_status"], "planned_only")
        self.assertEqual(reverse_atom["claim_type"], "reverse_query.last_writer")
        self.assertEqual(reverse_atom["proof_status"], "instruction_observed")
        self.assertEqual(reverse_atom["source_report"], "effect_trace.json")
        self.assertTrue(any(atom["claim_type"] == "effect.memory_write" for atom in result["evidence_atoms"]))
        self.assertTrue(any(atom["claim_type"] == "reverse_query.last_writer" for atom in graph_edge["evidence_atoms"]))

