    def test_reverse_query_preserves_compact_write_index_operand_history(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 UnitFunc\n", encoding="utf-8")
            (root / "instruction_trace.jsonl").write_text(
                json.dumps(
                    {
                        "seq": 0,
                        "bank": 1,
                        "pc": 0x4000,
                        "pc_label": "UnitFunc",
                        "opcode": 0xEA,
                        "operand": [0x41, 0xD1],
                        "regs": {"A": 0x2A, "SP": 0xDFF0},
                    }
                )
                + "\n",
                encoding="utf-8",
            )

            effect = build_effect_trace_report(
                traces=("instruction_trace.jsonl",),
                symbols_path="test.sym",
                root=root,
            )
            (root / "compact_effect.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_effect_trace",
                        "valid": True,
                        "write_index": effect["write_index"],
                    }
                ),
                encoding="utf-8",
            )
            reverse = build_reverse_query_report(
                reports=("compact_effect.json",),
                addresses=("D141",),
                symbols_path="test.sym",
                root=root,
            )

        result = reverse["results"][0]
        last_writer = result["last_writer"]

        self.assertTrue(reverse["valid"])
        self.assertEqual(result["last_writer_pc"], "01:4000")
        self.assertEqual(result["last_value_hex"], "2A")
        self.assertEqual(reverse["validation_summary"]["index_history_only"], 1)
        self.assertEqual(result["validation"]["status"], "index_history_only")
        self.assertFalse(result["validation"]["validated"])
        self.assertEqual(result["validation_routes"][0]["id"], "rerun_reverse_query")
        self.assertTrue(result["validation_routes"][0]["runnable"])
        self.assertEqual(result["validation_routes"][0]["proof_status"], "planned_only")
        self.assertEqual(result["validation_routes"][0]["expected_proof_status"], "instruction_observed")
        route_spec = result["validation_routes"][0]["command_spec"]
        self.assertEqual(route_spec["kind"], "command_spec")
        self.assertEqual(route_spec["rendered"], result["validation_routes"][0]["command"])
        self.assertEqual(route_spec["runnable"], result["validation_routes"][0]["runnable"])
        self.assertEqual(route_spec["status"], result["validation_routes"][0]["status"])
        self.assertEqual(route_spec["actual_proof_status"], result["validation_routes"][0]["proof_status"])
        self.assertEqual(route_spec["expected_proof_status"], result["validation_routes"][0]["expected_proof_status"])
        self.assertEqual(route_spec["expected_outputs"], [result["validation_routes"][0]["produces"]])
        self.assertFalse(route_spec["has_placeholders"])
        self.assertIn("compact_effect.json", route_spec["required_inputs"])
        self.assertIn("test.sym", route_spec["required_inputs"])
        self.assertIn("command string parsed without placeholders", route_spec["trust_checks"])
        self.assertGreater(len(route_spec["argv"]), 0)
        self.assertEqual(last_writer["pc_label"], "UnitFunc")
        self.assertEqual(last_writer["address"], "D141")
        self.assertEqual(last_writer["address_key"], "wram:--:D141")
        self.assertEqual(last_writer["source_operands"][0]["name"], "a")
        self.assertEqual(last_writer["source_operands"][0]["value"], "2A")

    def test_reverse_query_validation_route_command_spec_marks_placeholder_inputs(self) -> None:
        target = parse_address_spec("D141").as_dict()
        target.update({"type": "address", "symbol": "", "label": "D141"})

        routes = result_validation_routes(
            target=target,
            source="",
            report={},
            validation={"proof_status": "planned_only"},
            symbols_path="test.sym",
            watch_size=1,
        )

        route = routes[0]
        spec = route["command_spec"]
        self.assertEqual(route["id"], "capture_effect_trace")
        self.assertEqual(spec["kind"], "command_spec")
        self.assertEqual(spec["rendered"], route["command"])
        self.assertEqual(spec["runnable"], route["runnable"])
        self.assertEqual(spec["status"], route["status"])
        self.assertEqual(spec["actual_proof_status"], route["proof_status"])
        self.assertEqual(spec["expected_proof_status"], route["expected_proof_status"])
        self.assertEqual(spec["expected_outputs"], [route["produces"]])
        self.assertTrue(spec["has_placeholders"])
        self.assertIn("<runtime-state>", spec["placeholders"])
        self.assertIn("<instruction-trace.jsonl>", spec["placeholders"])
        self.assertIn("<runtime-state>", spec["required_inputs"])
        self.assertIn("<instruction-trace.jsonl>", spec["required_inputs"])
        self.assertIn("placeholders must be replaced before execution", spec["trust_checks"])
        self.assertEqual(spec["status"], "planned")
        self.assertFalse(spec["runnable"])

    def test_reverse_query_raw_banked_address_requires_exact_effect_key(self) -> None:
        def write_entry(*, key: str, space: str, seq: int, pc: str, value: str) -> dict[str, Any]:
            return {
                "address_key": key,
                "space": space,
                "address": "D141",
                "read_count": 0,
                "write_count": 1,
                "last_writer_seq": seq,
                "last_writer_pc": pc,
                "last_value_hex": value,
                "history": [],
            }

        def event(*, key: str, space: str, seq: int, pc: str, value: str) -> dict[str, Any]:
            return {
                "seq": seq,
                "pc_bank_address": pc,
                "pc_label": f"Writer{seq}",
                "effects": [
                    {
                        "kind": "memory_write",
                        "access": "write",
                        "space": space,
                        "address": 0xD141,
                        "address_hex": "D141",
                        "address_key": key,
                        "operation": f"write {value}",
                        "value_hex": value,
                    }
                ],
            }

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "test.sym").write_text("01:4000 Writer1\n01:4003 Writer2\n", encoding="utf-8")
            unbanked_entry = write_entry(
                key="wram:--:D141",
                space="wram",
                seq=1,
                pc="01:4000",
                value="2A",
            )
            unbanked_event = event(
                key="wram:--:D141",
                space="wram",
                seq=1,
                pc="01:4000",
                value="2A",
            )
            banked_entry = write_entry(
                key="wramx:01:D141",
                space="wramx",
                seq=2,
                pc="01:4003",
                value="55",
            )
            banked_event = event(
                key="wramx:01:D141",
                space="wramx",
                seq=2,
                pc="01:4003",
                value="55",
            )
            (root / "effect_unbanked.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_effect_trace",
                        "valid": True,
                        "write_index": [unbanked_entry],
                        "events": [unbanked_event],
                    }
                ),
                encoding="utf-8",
            )
            (root / "effect_mixed.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_effect_trace",
                        "valid": True,
                        "write_index": [unbanked_entry, banked_entry],
                        "events": [unbanked_event, banked_event],
                    }
                ),
                encoding="utf-8",
            )

            missing = build_reverse_query_report(
                reports=("effect_unbanked.json",),
                addresses=("01:$D141",),
                symbols_path="test.sym",
                root=root,
            )
            banked = build_reverse_query_report(
                reports=("effect_mixed.json",),
                addresses=("01:$D141",),
                symbols_path="test.sym",
                root=root,
            )

        self.assertTrue(missing["valid"])
        self.assertEqual(missing["result_count"], 0)
        self.assertTrue(banked["valid"])
        self.assertEqual(banked["result_count"], 1)
        self.assertEqual(banked["results"][0]["matched_address_key"], "wramx:01:D141")
        self.assertEqual(banked["results"][0]["last_writer_pc"], "01:4003")
        self.assertEqual(banked["results"][0]["last_value_hex"], "55")
        self.assertEqual(banked["results"][0]["last_writer"]["address_key"], "wramx:01:D141")
        self.assertEqual(banked["results"][0]["last_writer"]["space"], "wramx")
        self.assertEqual([item["value_hex"] for item in banked["results"][0]["history"]], ["55"])

