        self.assertIn("last_wrote", relations)
        self.assertIn("answers_last_write", relations)
        self.assertIn("feeds_write", relations)
        self.assertIn("proves_taint_to", relations)
        self.assertIn("triggers_side_effect", relations)
        self.assertIn("address_key=wramx:01:D141", evidence_text)
        self.assertIn("value=0x2A", evidence_text)
        self.assertIn("source=register:a=0x2A", evidence_text)
        self.assertIn("taint_proven", graph["proof_status_counts"])
        self.assertIn("move_power", path_titles)
        self.assertIn("answers_last_write", path_titles)
        self.assertTrue(graph_findings)
        self.assertIn("causal_graph_path", {event["event_type"] for event in visualization["timeline"]})
        self.assertIn("node_count", static["content"])

