    def test_causal_graph_node_keeps_proof_status_by_source(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "packet.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_playtest_packet",
                        "valid": True,
                        "packet_id": "playtest-freeze",
                        "proof_status": "planned_only",
                        "watch_symbols": ["wCurDamage"],
                    }
                ),
                encoding="utf-8",
            )
            (root / "dynamic.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_dynamic_taint_report",
                        "valid": True,
                        "paths": [
                            {
                                "id": "dynamic_taint_path_0001",
                                "title": "move_power -> wCurDamage",
                                "target": "wCurDamage",
                                "proof_status": "taint_proven",
                                "related_symbols": ["move_power", "wCurDamage"],
                                "evidence": ["taint=move_power"],
                                "score": 92,
                                "confidence": 0.9,
                            }
                        ],
                    }
                ),
                encoding="utf-8",
            )
            graph = build_causal_graph_report(reports=("packet.json", "dynamic.json"), root=root)
            (root / "causal_graph.json").write_text(json.dumps(graph), encoding="utf-8")
            visualization = build_visualization_report(reports=("causal_graph.json",), root=root)

        node = next(item for item in graph["nodes"] if item["label"] == "wCurDamage")
        visual_node = next(item for item in visualization["graph"]["nodes"] if item["label"] == "wCurDamage")
        planned_edge = next(edge for edge in graph["edges"] if edge["relation"] == "targets_symbol")
        proven_edge = next(edge for edge in graph["edges"] if edge["relation"] == "proves_taint_to")

        self.assertEqual(node["proof_status"], "taint_proven")
        self.assertEqual(
            node["proof_status_by_source"],
            {"dynamic.json": "taint_proven", "packet.json": "planned_only"},
        )
        self.assertEqual(node["proof_summary"]["max"], "taint_proven")
        self.assertEqual(node["proof_summary"]["min"], "planned_only")
        self.assertEqual(node["proof_summary"]["source_count"], 2)
        self.assertEqual(planned_edge["proof_status"], "planned_only")
        self.assertEqual(proven_edge["proof_status"], "taint_proven")
        self.assertEqual(visual_node["proof_status_by_source"], node["proof_status_by_source"])
        self.assertEqual(visual_node["proof_summary"], node["proof_summary"])

