    def test_rank_and_impact_preserve_causal_path_proof_summary(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            graph_report = {
                "schema_version": 1,
                "kind": "unified_debugger_causal_graph",
                "valid": True,
                "nodes": [],
                "edges": [],
                "paths": [
                    {
                        "title": "move_power -> planned route -> wCurDamage",
                        "proof_status": "planned_only",
                        "score": 88,
                        "confidence": 0.72,
                        "evidence": ["edge detail"],
                        "proof_summary": {
                            "max": "taint_proven",
                            "min": "planned_only",
                            "edge_count": 3,
                        },
                        "proof_vector": [
                            {
                                "relation": "taints_register",
                                "proof_status": "taint_proven",
                                "source": "dynamic.json",
                            },
                            {
                                "relation": "plans_evidence_route",
                                "proof_status": "planned_only",
                                "source": "packet.json",
                            },
                        ],
                    }
                ],
            }
            (root / "causal_graph.json").write_text(json.dumps(graph_report), encoding="utf-8")
            ranked = rank_findings(reports=("causal_graph.json",), root=root)
            impact = build_impact_report(reports=("causal_graph.json",), root=root)

        ranked_path = next(item for item in ranked["findings"] if item["type"] == "causal_path")
        impact_path = next(item for item in impact["items"] if item["type"] == "causal_path")
        ranked_evidence = "\n".join(ranked_path["evidence"])
        impact_evidence = "\n".join(impact_path["evidence"])

        self.assertEqual(ranked_path["proof_status"], "planned_only")
        self.assertEqual(impact_path["proof_status"], "planned_only")
        self.assertIn("proof_min=planned_only", ranked_evidence)
        self.assertIn("proof_max=taint_proven", ranked_evidence)
        self.assertIn("proof_edge=plans_evidence_route:planned_only", ranked_evidence)
        self.assertIn("proof_min=planned_only", impact_evidence)
        self.assertIn("proof_edge=plans_evidence_route:planned_only", impact_evidence)

