    def test_instruction_trace_execution_replays_input_log_buttons(self) -> None:
        class FakeRegisters:
            A = 0x12
            F = 0
            B = 0
            C = 0
            D = 0
            E = 0
            H = 0xD1
            L = 0x41
            SP = 0xFFFE
            PC = 0x4000

        class FakeMemory:
            def __init__(self) -> None:
                self.values = {0xFF70: 1, 0xFF4F: 0, 0xD141: 0}

            def __getitem__(self, key):
                return self.values.get(key, 0)

            def __setitem__(self, key, value) -> None:
                self.values[key] = value

        class FakePyBoy:
            def __init__(self) -> None:
                self.register_file = FakeRegisters()
                self.memory = FakeMemory()
                self.buttons: list[tuple[str, int]] = []
                self.callbacks: list[Any] = []

            def hook_register(self, _bank, _pc, callback, _ctx) -> None:
                self.callbacks.append(callback)

            def hook_deregister(self, _bank, _pc) -> None:
                pass

            def button(self, button_name: str, *, delay: int) -> None:
                self.buttons.append((button_name, delay))

            def tick(self, count=1, *_args) -> None:
                for _ in range(count):
                    for callback in self.callbacks:
                        callback(None)

            def stop(self, save=False) -> None:
                self.stopped = True

        pyboy = FakePyBoy()
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            rom = bytearray(0x8000)
            rom[0x4000] = 0xC9
            (root / "test.gbc").write_bytes(bytes(rom))
            (root / "test.sym").write_text("01:4000 UnitFunc\n00:D141 wCurDamage\n", encoding="utf-8")
            (root / "bug.inputs").write_text("A\nWAIT 1\nB 2\n", encoding="utf-8")

            with patch("tools.debugger.instruction_trace.trace_runtime.open_pyboy", return_value=pyboy):
                report = build_instruction_trace_report(
                    function_symbols=("UnitFunc",),
                    watch_addresses=("$D141",),
                    rom_path="test.gbc",
                    symbols_path="test.sym",
                    input_logs=("bug.inputs",),
                    frames=4,
                    execute=True,
                    require_hit=True,
                    root=root,
                )

        self.assertTrue(report["valid"])
        self.assertEqual(pyboy.buttons, [("a", 1), ("b", 2)])
        self.assertGreaterEqual(report["captured_frame_count"], 1)
        self.assertEqual(report["input_playback"]["button_event_count"], 2)
        self.assertEqual(report["played_input_count"], 3)

