    def test_replay_and_investigate_consume_minimized_input_log_artifact(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "pokegold.sym").write_text("01:D141 wCurDamage\n", encoding="utf-8")
            (root / "minimized.inputs").write_text("WAIT 1\nA\n", encoding="utf-8")
            (root / "minimize.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_minimization_plan",
                        "valid": True,
                        "input_log_minimization": {
                            "attempted": True,
                            "preserved": True,
                            "written": True,
                            "out_input_log": "minimized.inputs",
                            "button_sample": ["A"],
                            "commands": [
                                "python -m tools.debugger replay --report packet.json --input-log minimized.inputs",
                                "python -m tools.debugger investigate --report packet.json --input-log minimized.inputs",
                            ],
                        },
                    }
                ),
                encoding="utf-8",
            )

            replay = build_replay_plan(reports=("minimize.json",), root=root)
            investigation = build_investigation_run(
                reports=("minimize.json",),
                out_dir="run",
                max_targets=1,
                max_cases=1,
                root=root,
            )

        replay_commands = "\n".join(replay["commands"])
        input_step_commands = "\n".join(
            command
            for step in investigation["steps"]
            if step["id"] == "00_input_reports"
            for command in step["commands"]
        )

        self.assertTrue(replay["valid"])
        self.assertEqual(replay["input_logs"], ["minimized.inputs"])
        self.assertEqual(replay["black_box_replay"]["input_log_count"], 1)
        self.assertEqual(replay["input_playback"]["button_sample"], ["A"])
        self.assertIn("input_log_minimized_artifact", {item["type"] for item in replay["signals"]})
        self.assertIn("--input-log minimized.inputs", replay_commands)
        self.assertTrue(investigation["valid"])
        self.assertEqual(investigation["derived_inputs"]["input_logs"], ["minimized.inputs"])
        self.assertEqual(investigation["effective_input_logs"], ["minimized.inputs"])
        self.assertIn("--input-log minimized.inputs", input_step_commands)

