        self.assertEqual(suggestion["related_addresses"], ["$D141", "DA11"])
        self.assertIn("sources=wScriptPos,UnitSeedRoutine,wScriptSeed", suggestion["notes"])
        self.assertIn("source_mems=DA11=wScriptSeed", suggestion["notes"])
        self.assertIn("tools.debugger content-state --scenario fuzz_cases.jsonl", counterexamples)
        self.assertIn("tools.debugger trace-instructions --report content_state.json", counterexamples)
        self.assertIn("tools.debugger dynamic-taint --trace trace.jsonl", counterexamples)
        self.assertIn("dynamic_taint_trace_synthesis_counterexamples", generation["test_suggestions"]["match_ids"])
        self.assertIn("tools.debugger dynamic-taint --trace trace.jsonl", generation_commands)
        self.assertIn("tools.debugger content-state --scenario fuzz_cases.jsonl", generation_commands)
        generated_route = next(item for item in generation["counterexamples"] if item["source"] == "suggest-tests")
        self.assertIn("UnitSeedRoutine", generated_route["related_symbols"])
        self.assertIn("wScriptSeed", generated_route["related_symbols"])
        self.assertIn("DA11", generated_route["related_addresses"])
        self.assertEqual(fuzz["counterexample_campaign_count"], 1)
        self.assertIn("fuzz_suggest_tests_instruction_trace_counterexamples", {campaign["id"] for campaign in fuzz["campaigns"]})
        self.assertIn("dynamic_counterexample", {case["fuzz_type"] for case in fuzz["fuzz_cases"]})
        self.assertIn("tools.debugger dynamic-taint --trace trace.jsonl", fuzz_commands)
        self.assertIn("tools.debugger dynamic-taint --trace trace.jsonl", fuzz_case_commands)
        fuzz_case_ids = [case["id"] for case in fuzz["fuzz_cases"]]
