        self.assertTrue(any("UnitSeedRoutine" in finding["related_symbols"] for finding in ranked_fuzz))
        self.assertTrue(any("wScriptSeed" in finding["related_symbols"] for finding in ranked_fuzz))
        self.assertTrue(any("DA11" in finding["related_addresses"] for finding in ranked_fuzz))
        self.assertTrue(impact_fuzz)
        self.assertTrue(any("D141" in item["related_addresses"] for item in impact_fuzz))
        self.assertTrue(any("DA11" in item["related_addresses"] for item in impact_fuzz))
        timeline_addresses = {
            address
            for event in visualization["timeline"]
            for address in event.get("addresses", [])
        }
        graph_labels = {node["label"] for node in visualization["graph"]["nodes"]}
        self.assertIn("$D141", timeline_addresses)
        self.assertIn("DA11", timeline_addresses)
        self.assertIn("wScriptPos", graph_labels)
        self.assertIn("wScriptSeed", graph_labels)
