    def test_generate_can_execute_bounded_semantic_commands(self) -> None:
        def mark_passed(step: dict[str, Any], **_kwargs: Any) -> None:
            step["status"] = "passed"
            step["returncode"] = 0
            step["elapsed_seconds"] = 0.01
            step["stdout_tail"] = ["generation command ok"]
            step["stderr_tail"] = []

        with patch("tools.debugger.generate.execute_step", side_effect=mark_passed) as execute:
            report = build_generation_plan(
                symbols=("wCurDamage",),
                max_cases=2,
                execute=True,
                max_execute_commands=2,
            )

        execution = report["execution"]

        self.assertTrue(report["valid"])
        self.assertTrue(report["executed"])
        self.assertTrue(execution["executed"])
        self.assertEqual(execution["step_count"], 2)
        self.assertEqual(execution["passed_count"], 2)
        self.assertEqual(execute.call_count, 2)

    def test_fuzz_reports_failed_bounded_execution(self) -> None:
        def mark_failed(step: dict[str, Any], **_kwargs: Any) -> None:
            step["status"] = "failed"
            step["returncode"] = 1
            step["elapsed_seconds"] = 0.01
            step["stdout_tail"] = []
            step["stderr_tail"] = ["fuzz command failed"]

        with patch("tools.debugger.generate.execute_step", side_effect=mark_failed):
            report = build_fuzz_plan(
                symbols=("wCurDamage",),
                max_cases=2,
                execute=True,
                max_execute_commands=1,
            )

        execution = report["execution"]

        self.assertFalse(report["valid"])
        self.assertTrue(report["executed"])
        self.assertEqual(execution["step_count"], 1)
        self.assertEqual(execution["failed_count"], 1)
        self.assertEqual(report["error_count"], 1)
        self.assertIn("fuzz:1", report["errors"][0])

