    def test_cli_content_scenarios_writes_json_and_manifest(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "audio" / "music").mkdir(parents=True)
            source = root / "audio" / "music" / "unit.asm"
            source.write_text(
                "\n".join(
                    [
                        "Music_Unit:",
                        "\tchannel_count 2",
                        "\tchannel 1, Music_Unit_Ch1",
                        "\tchannel 2, Music_Unit_Ch2",
                        "",
                        "Music_Unit_Ch1:",
                        "\ttempo 144",
                        "\tnote_type 12, 11, 3",
                        "\toctave 3",
                        "\tnote C_, 4",
                        "\tsound_ret",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            out = root / "content_scenarios.json"
            manifest = root / "content_scenarios.jsonl"

            with redirect_stdout(io.StringIO()):
                code = debugger_main(
                    [
                        "content-scenarios",
                        "--source-file",
                        str(source),
                        "--out-scenarios",
                        str(manifest),
                        "--json-out",
                        str(out),
                    ]
                )

            data = json.loads(out.read_text(encoding="utf-8"))
            rows = [
                json.loads(line)
                for line in manifest.read_text(encoding="utf-8").splitlines()
                if line.strip()
            ]

        self.assertEqual(code, 0)
        self.assertEqual(data["kind"], "unified_debugger_content_scenarios")
        audio_rows = [row for row in rows if row["scenario_type"] == "audio_channel_block"]
        stream_rows = [row for row in rows if row["scenario_type"] == "audio_command_stream"]
        self.assertEqual(len(audio_rows), 1)
        self.assertEqual(len(stream_rows), 1)
        self.assertNotIn("script_command_stream", {row["scenario_type"] for row in rows})
        self.assertEqual(data["scenario_count"], len(rows))
        self.assertEqual(audio_rows[0]["behavioral_probe_count"], len(audio_rows[0]["behavioral_probes"]))
        self.assertIn("content_replay_route", {probe["id"] for probe in audio_rows[0]["behavioral_probes"]})
        self.assertIn("content_runtime_watch_route", {probe["id"] for probe in audio_rows[0]["behavioral_probes"]})
        self.assertIn("content_state_materialization_route", {probe["id"] for probe in audio_rows[0]["behavioral_probes"]})
        self.assertIn("content_output_dynamic_taint_route", {probe["id"] for probe in audio_rows[0]["behavioral_probes"]})
        self.assertIn("wMusicID", audio_rows[0]["state_preconditions"][0]["watch_symbols"])
        self.assertIn("wMusicID", {output.get("state_symbol") for output in audio_rows[0]["outputs"]})
        self.assertIn("$FF12", {output.get("address") for output in audio_rows[0]["outputs"]})
        self.assertIn("wMusicID", audio_rows[0]["runtime_targets"]["watch_symbols"])
        self.assertEqual(stream_rows[0]["trigger"]["stream"], "Music_Unit_Ch1")
        self.assertIn("ParseMusic", stream_rows[0]["runtime_targets"]["trace_symbols"])
        self.assertIn("wMusicID", {output.get("state_symbol") for output in stream_rows[0]["outputs"]})
        self.assertIn("$FF12", {output.get("address") for output in stream_rows[0]["outputs"]})
        self.assertIn("content_output_dynamic_taint_route", {probe["id"] for probe in stream_rows[0]["behavioral_probes"]})
        self.assertIn("--watch-symbol wMusicID", "\n".join(data["commands"]))
        self.assertIn("--sink-address FF12", "\n".join(data["commands"]))
        self.assertIn("dynamic-taint --report .local\\tmp\\debugger_content_state_", "\n".join(data["commands"]))
        self.assertIn("contains=channel_count", "\n".join(data["commands"]))
        self.assertIn("contains=Music_Unit_Ch1", "\n".join(data["commands"]))

