    def test_investigation_derives_targets_from_fuzz_campaign_reports(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "scripts").mkdir()
            (root / "test.sym").write_text(
                "01:D141 wScriptPos\n01:4000 RunScriptCommand\n",
                encoding="utf-8",
            )
            (root / "scripts" / "unit_script.asm").write_text(
                "UnitScript:\n\topentext\n\tclosetext\n\tend\n",
                encoding="utf-8",
            )
            (root / "fuzz.json").write_text(
                json.dumps(
                    {
                        "kind": "unified_debugger_fuzz_plan",
                        "valid": True,
                        "campaigns": [
                            {
                                "id": "fuzz_suggest_tests_instruction_trace_counterexamples",
                                "surface": "instruction_trace",
                                "proof_level": "dynamic_trace_planned",
                                "related_symbols": ["RunScriptCommand", "wScriptPos"],
                                "related_addresses": ["$D141"],
                                "changed_files": ["scripts/unit_script.asm"],
                                "commands": [
                                    "python -m tools.debugger dynamic-taint --trace trace.jsonl --sink-symbol wScriptPos --sink-address D141"
                                ],
                            }
                        ],
                        "fuzz_cases": [],
                    }
                ),
                encoding="utf-8",
            )

            report = build_investigation_run(
                symbols_path="test.sym",
                reports=("fuzz.json",),
                out_dir="run",
                max_targets=4,
                max_cases=2,
                root=root,
            )
            replay = json.loads((root / "run" / "03_replay.json").read_text(encoding="utf-8"))
            generate = json.loads((root / "run" / "09_generate.json").read_text(encoding="utf-8"))

        input_step = next(step for step in report["steps"] if step["id"] == "00_input_reports")
        input_step_commands = "\n".join(input_step["commands"])

        self.assertTrue(report["valid"])
        self.assertIn("00_input_reports", {step["id"] for step in report["steps"]})
        self.assertIn("scripts/unit_script.asm", report["changed_files"])
        self.assertIn("RunScriptCommand", report["symbols"])
        self.assertIn("wScriptPos", report["effective_watch_symbols"])
        self.assertIn("$D141", report["addresses"])
        self.assertIn("scripts/unit_script.asm", replay["replay_targets"]["source_files"])
        self.assertIn("wScriptPos", replay["replay_targets"]["watch_symbols"])
        self.assertIn("$D141", replay["replay_targets"]["watch_addresses"])
        self.assertIn("scripts/unit_script.asm", replay["setup_plan"]["changed_files"])
        self.assertIn("--watch-address D141", "\n".join(replay["commands"]))
        self.assertIn("scripts/unit_script.asm", generate["changed_files"])
        self.assertIn("RunScriptCommand", generate["symbols"])
        self.assertIn("dynamic-taint --trace trace.jsonl", input_step_commands)
        self.assertLess(
            input_step_commands.index("dynamic-taint --trace trace.jsonl"),
            input_step_commands.index("tools.debugger audit")
            if "tools.debugger audit" in input_step_commands
            else len(input_step_commands),
        )

