        self.assertIn("wCurDamage", replay["replay_targets"]["watch_symbols"])
        self.assertIn("D141", replay["replay_targets"]["watch_addresses"])
        self.assertIn("BattleCommand_Test", localize_candidates)
        self.assertIn("wCurDamage", localize_candidates)
        self.assertIn("D141", localize_candidates)
        self.assertIn("provenance --report minimize.json", input_step_commands)
        self.assertIn("taint --report minimize.json", input_step_commands)
        self.assertIn("slice --report minimize.json", input_step_commands)
        self.assertIn("replay --report minimized_state_space.json --watch-address D141", input_step_commands)

