        ready_item = next(item for item in impact["items"] if item["type"] == "content_state_ready")

        self.assertTrue(ranked["valid"])
        self.assertIn("content_state_ready", ranked_types)
        self.assertIn("content_state_blocked", ranked_types)
        self.assertIn("content_state_executed", ranked_types)
        self.assertEqual(ready_finding["proof_status"], "planned_only")
        self.assertEqual(executed_finding["proof_status"], "state_materialized")
        self.assertIn("save_state_delta_changed_bytes=2", executed_finding["evidence"])
        self.assertIn("save_state_delta_offsets=1,3", executed_finding["evidence"])
        self.assertIn("save_state_delta_changed_bytes=2", executed_item["evidence"])
        self.assertIn("save_state_delta_offsets=1,3", executed_item["evidence"])
